-- Brainrots Hub v10.1 - FULL + Remove Lava Stronger by Phúc
-- Load Rayfield with fallback
local Rayfield
local success = pcall(function()
    Rayfield = loadstring(game:HttpGet('https://sirius.menu/rayfield'))()
end)
if not success or not Rayfield then
    pcall(function()
        Rayfield = loadstring(game:HttpGet('https://raw.githubusercontent.com/shlexware/Rayfield/main/source'))()
    end)
end
if not Rayfield then
    warn("Rayfield load failed! Try different executor.")
    return
end

local Window = Rayfield:CreateWindow({
   Name = 'Brainrots Hub NHẬT',
   LoadingTitle = 'Đang tải...',
   LoadingSubtitle = 'by x Nhật - Destroy Folder + Material',
   ConfigurationSaving = {Enabled = true, FolderName = 'BrainrotHub', FileName = 'Config'},
   KeySystem = false
})

local player = game.Players.LocalPlayer
local BaseCFrame = nil
local targetBrainrotType = "Celestial"

local RS = game:GetService("RunService")
local UIS = game:GetService("UserInputService")

local godConn, infJumpConn, collectLoop, rebirthLoop, stealLoop
local lavaConn1 = nil
local lavaConn2 = nil
local lastLavaRemove = 0
local lastSteal = 0  -- FIX: khai báo để Auto Steal không lỗi
local promptConn = nil

-- Save Base
local function saveBase(char)
   if char and char:FindFirstChild("HumanoidRootPart") and not BaseCFrame then
      task.wait(1)
      BaseCFrame = char.HumanoidRootPart.CFrame
      Rayfield:Notify({Title = 'Base Saved!', Duration = 3})
   end
end
if player.Character then saveBase(player.Character) end
player.CharacterAdded:Connect(saveBase)

-- God Mode
local function applyGod(char)
   local hum = char and char:FindFirstChildOfClass("Humanoid")
   if hum then
      hum.MaxHealth = math.huge
      hum.Health = math.huge
      hum:GetPropertyChangedSignal("Health"):Connect(function()
         if hum.Health < hum.MaxHealth then hum.Health = hum.MaxHealth end
      end)
   end
end
local function restoreHum(char)
   local hum = char and char:FindFirstChildOfClass("Humanoid")
   if hum then hum.MaxHealth = 100 hum.Health = 100 end
end

-- Brainrots Helpers
local function getFolder(tp)
   local gf = workspace:FindFirstChild("GameFolder") or workspace
   local brNames = {"Brainrots", "BrainRots", "Brainrot"}
   local br
   for _, n in brNames do br = gf:FindFirstChild(n) if br then break end end
   if not br then return nil end
   local fNames = {}
   if tp == "Celestial" then fNames = {"Celestial", "Celestials"}
   elseif tp == "Secret" then fNames = {"Secret", "Secrets"}
   elseif tp == "God" then fNames = {"Godly", "God", "Divine"}
   end
   for _, fn in fNames do local f = br:FindFirstChild(fn) if f then return f end end
   return nil
end

local function findRichest(folder)
   if not folder then return nil end
   local richest, maxV, fallback = nil, -1, nil
   for _, obj in folder:GetChildren() do
      if obj:IsA("Model") or obj:IsA("Folder") then
         fallback = fallback or obj
         local ls = obj:FindFirstChild("leaderstats")
         if ls then
            local v = ls:FindFirstChild("Farm") or ls:FindFirstChild("Cash") or ls:FindFirstChild("Money") or ls:FindFirstChild("Value")
            local val = v and v.Value or 0
            if val > maxV then maxV = val richest = obj end
         end
      end
   end
   return richest or fallback, maxV
end

local function tpTo(obj)
   local char = player.Character
   if not char or not char:FindFirstChild("HumanoidRootPart") then return false end
   local root = obj:FindFirstChild("HumanoidRootPart") or obj:FindFirstChildWhichIsA("BasePart")
   if root then
      char.HumanoidRootPart.CFrame = root.CFrame * CFrame.new(0,5,-5)
      return true
   end
   return false
end

-- Instant Proximity Prompt Helper
local function setupPrompt(prompt, instant)
   if not prompt:IsA("ProximityPrompt") then return end
   prompt.HoldDuration = instant and 0 or 2
   prompt.RequiresLineOfSight = not instant
   prompt.MaxActivationDistance = instant and 200 or 10
end

-- Teleports Tab
local tpTab = Window:CreateTab("Teleports")
tpTab:CreateSection("TP Chức Năng")

tpTab:CreateButton({Name = "về Base", Callback = function()
   local char = player.Character
   if not char or not char:FindFirstChild("HumanoidRootPart") then return Rayfield:Notify({Title="Lỗi", Content="Chưa load char!", Duration=3}) end
   if BaseCFrame then char.HumanoidRootPart.CFrame = BaseCFrame + Vector3.new(0,5,0) Rayfield:Notify({Title="TP Base OK!", Duration=3})
   else Rayfield:Notify({Title="Chưa lưu Base!", Duration=4}) end
end})

tpTab:CreateButton({Name = "Base Manual", Callback = function()
   local char = player.Character
   if char and char:FindFirstChild("HumanoidRootPart") then BaseCFrame = char.HumanoidRootPart.CFrame Rayfield:Notify({Title="Base Set OK!", Duration=3}) end
end})

tpTab:CreateButton({Name = "Celestial ", Callback = function()
   local f = getFolder("Celestial")
   if not f then return Rayfield:Notify({Title="Không tìm Celestial!", Duration=4}) end
   local r, v = findRichest(f)
   if r and tpTo(r) then Rayfield:Notify({Title="TP Celestial OK! ("..(v or "?")..")", Duration=3})
   else Rayfield:Notify({Title="Không tìm richest Celestial!", Duration=4}) end
end})

tpTab:CreateButton({Name = " Secret ", Callback = function()
   local f = getFolder("Secret")
   if not f then return Rayfield:Notify({Title="Không tìm Secret!", Duration=4}) end
   local r, v = findRichest(f)
   if r and tpTo(r) then Rayfield:Notify({Title="TP Secret OK! ("..(v or "?")..")", Duration=3})
   else Rayfield:Notify({Title="Không tìm richest Secret!", Duration=4}) end
end})

tpTab:CreateButton({Name = "TP God Richest", Callback = function()
   local f = getFolder("God")
   if not f then return Rayfield:Notify({Title="Không tìm God!", Duration=4}) end
   local r, v = findRichest(f)
   if r and tpTo(r) then Rayfield:Notify({Title="TP God OK! ("..(v or "?")..")", Duration=3})
   else Rayfield:Notify({Title="Không tìm richest God!", Duration=4}) end
end})

-- Auto Farm Tab
local farmTab = Window:CreateTab("Auto Farm")
farmTab:CreateSection("Farm Low Lag")

farmTab:CreateDropdown({
   Name = "Chọn Loại Brainrot để Steal",
   Options = {"Celestial", "Secret", "God"},
   CurrentOption = {"Celestial"},
   Callback = function(opt) targetBrainrotType = opt[1] Rayfield:Notify({Title="Target: "..targetBrainrotType, Duration=2}) end
})

farmTab:CreateToggle({
   Name = "Auto Steal Richest (TP + Fire Prompt)",
   Callback = function(val)
      if val then
         local cnt = 0
         stealLoop = RS.Heartbeat:Connect(function()
            if tick() - lastSteal < 0.8 then return end
            lastSteal = tick()
            local char = player.Character
            if not char or not char:FindFirstChild("HumanoidRootPart") then return end
            local f = getFolder(targetBrainrotType)
            if not f then return end
            local r = findRichest(f)
            if not r then return end
            tpTo(r)
            local hrp = char.HumanoidRootPart
            local fired = false
            for _, p in workspace:GetDescendants() do
               if p:IsA("ProximityPrompt") and p.Enabled then
                  local pp = p.Parent:IsA("BasePart") and p.Parent or p:FindFirstAncestorWhichIsA("BasePart")
                  if pp and (pp.Position - hrp.Position).Magnitude < 150 then
                     fireproximityprompt(p)
                     cnt += 1
                     fired = true
                     if cnt % 5 == 0 then Rayfield:Notify({Title="Stolen: "..cnt.." "..targetBrainrotType, Duration=3}) end
                     break
                  end
               end
            end
            if not fired then task.wait(0.1) end
         end)
         Rayfield:Notify({Title="Auto Steal ON! (Faster + Longer Range)", Duration=5})
      else
         if stealLoop then stealLoop:Disconnect() end
         Rayfield:Notify({Title="Auto Steal OFF", Duration=3})
      end
   end
})

farmTab:CreateToggle({
   Name = "Collect Cash",
   Callback = function(val)
      if val then
         collectLoop = RS.Heartbeat:Connect(function()
            local lastFire = 0
            if tick() - lastFire < 0.3 then return end
            lastFire = tick()
            local fired = 0
            for _, p in workspace:GetDescendants() do
               if fired >= 5 then break end
               if p:IsA("ProximityPrompt") and p.Enabled and (p.Name:lower():find("collect") or p.Name:lower():find("claim") or p.Name:lower():find("cash") or p.Name:lower():find("money")) then
                  fireproximityprompt(p)
                  fired += 1
               end
            end
         end)
         Rayfield:Notify({Title="Auto Collect ON!", Duration=3})
      else
         if collectLoop then collectLoop:Disconnect() end
         Rayfield:Notify({Title="Auto Collect OFF", Duration=3})
      end
   end
})

farmTab:CreateToggle({
   Name = "Auto Rebirth",
   Callback = function(val)
      if val then
         local lastRebirth = 0
         rebirthLoop = RS.Heartbeat:Connect(function()
            if tick() - lastRebirth < 1.5 then return end
            lastRebirth = tick()
            local fired = false
            for _, g in player.PlayerGui:GetDescendants() do
               if (g:IsA("TextButton") or g:IsA("ImageButton")) and g.Visible and (g.Text or g.Name):lower():find("rebirth") then
                  firesignal(g.Activated or g.MouseButton1Click)
                  fired = true
                  break
               end
            end
            if not fired then
               for _, p in workspace:GetDescendants() do
                  if p:IsA("ProximityPrompt") and p.Enabled and p.ObjectText:lower():find("rebirth") then
                     fireproximityprompt(p)
                     fired = true
                     break
                  end
               end
            end
         end)
         Rayfield:Notify({Title="Auto Rebirth ON!", Duration=3})
      else
         if rebirthLoop then rebirthLoop:Disconnect() end
         Rayfield:Notify({Title="Auto Rebirth OFF", Duration=3})
      end
   end
})

